#[inline]
unsafe fn copy_kernel_bytes(dst: *mut u8, src: *const u8, len: usize) {
    #[cfg(target_arch = "loongarch64")]
    {
        let mut offset = 0usize;
        while offset < len {
            let byte = unsafe { core::ptr::read(src.add(offset)) };
            unsafe { core::ptr::write(dst.add(offset), byte) };
            offset += 1;
        }
    }
    #[cfg(not(target_arch = "loongarch64"))]
    unsafe {
        core::ptr::copy_nonoverlapping(src, dst, len);
    }
}

/// The virtual memory address space.
pub struct AddrSpace {
    va_range: VirtAddrRange,
    areas: MemorySet<Backend>,
    pt: PageTable,
}

impl AddrSpace {
    fn detach_shared_kernel_mappings_in_pt(pt: &mut PageTable) {
        if cfg!(target_arch = "aarch64") || cfg!(target_arch = "loongarch64") {
            return;
        }
        let kernel_aspace = KERNEL_ASPACE.lock();
        pt.clear_root_entries(kernel_aspace.base(), kernel_aspace.size());
    }

    /// Returns the address space base.
    pub const fn base(&self) -> VirtAddr {
        self.va_range.start
    }

    /// Returns the address space end.
    pub const fn end(&self) -> VirtAddr {
        self.va_range.end
    }

    /// Returns the address space size.
    pub fn size(&self) -> usize {
        self.va_range.size()
    }

    /// Returns the number of tracked mapped areas.
    pub fn area_count(&self) -> usize {
        self.areas.len()
    }

    /// Returns the total virtual size covered by tracked areas.
    pub fn total_area_size(&self) -> usize {
        self.areas.iter().map(|area| area.size()).sum()
    }

    /// Returns the reference to the inner page table.
    pub const fn page_table(&self) -> &PageTable {
        &self.pt
    }

    /// Returns the root physical address of the inner page table.
    pub const fn page_table_root(&self) -> PhysAddr {
        self.pt.root_paddr()
    }

    /// Checks if the address space contains the given address range.
    pub fn contains_range(&self, start: VirtAddr, size: usize) -> bool {
        VirtAddrRange::try_from_start_size(start, size)
            .is_some_and(|range| self.va_range.contains_range(range))
    }

    /// Creates a new empty address space.
    pub(crate) fn new_empty(base: VirtAddr, size: usize) -> AxResult<Self> {
        Ok(Self {
            va_range: VirtAddrRange::from_start_size(base, size),
            areas: MemorySet::new(),
            pt: PageTable::try_new().map_err(|_| AxError::NoMemory)?,
        })
    }

    /// Copies page table mappings from another address space.
    ///
    /// It copies the page table entries only rather than the memory regions,

        Self {
            si_signo: signum as i32,
            ..Default::default()
        }
    }

    fn from_sender(signum: usize, si_code: i32, sender_pid: i32, sender_uid: u32) -> Self {
        let mut info = Self {
            si_signo: signum as i32,
            si_code,
            ..Default::default()
        };
        info.fields[..4].copy_from_slice(&sender_pid.to_ne_bytes());
        info.fields[4..8].copy_from_slice(&sender_uid.to_ne_bytes());
        info
    }

    pub(crate) fn queued(signum: usize, sender_pid: i32, sender_uid: u32, value: usize) -> Self {
        let mut info = Self::from_sender(signum, SI_QUEUE, sender_pid, sender_uid);
        info.fields[8..16].copy_from_slice(&(value as u64).to_ne_bytes());
        info
    }

    pub(crate) fn tkill(signum: usize, sender_pid: i32, sender_uid: u32) -> Self {
        Self::from_sender(signum, SI_TKILL, sender_pid, sender_uid)
    }

    pub(crate) fn user(signum: usize, sender_pid: i32, sender_uid: u32) -> Self {
        Self::from_sender(signum, SI_USER, sender_pid, sender_uid)
    }

    pub(crate) fn signal_value(&self) -> usize {
        u64::from_ne_bytes(self.fields[8..16].try_into().unwrap()) as usize
    }

    pub(crate) fn signo(&self) -> i32 {
        self.si_signo
    }
}

